def find_latest_qa_report(project_root: Path) -> Optional[Path]:
    reports_dir = project_root / "qa_reports"
    if not reports_dir.exists():
        return None
    reports = sorted(reports_dir.glob("qa_report_*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return reports[0] if reports else None


def report_to_dict(report: FixerReport) -> Dict[str, Any]:
    return {
        "generated_at": report.generated_at,
        "project_root": report.project_root,
        "qa_report_path": report.qa_report_path,
        "applied_count": report.applied_count,
        "skipped_count": report.skipped_count,
        "failed_count": report.failed_count,
        "actions": [asdict(a) for a in report.actions],
        "escalations": report.escalations,
    }


def main() -> None:
    project_root = Path(os.environ.get("GH_PROJECT_ROOT", ".")).resolve()
    config_path = Path(os.environ.get("GH_FIXER_CONFIG", "gh_fixer_config.json"))
    print(f"[Fixer] Loading config from {config_path}")

    if config_path.exists():
        config = json.loads(read_text(config_path))
    else:
        config = default_config()
        save_json(config_path, config)
        print(f"Created fixer config at {config_path}")

    qa_report_env = os.environ.get("GH_QA_REPORT")
    qa_report_path = Path(qa_report_env).resolve() if qa_report_env else find_latest_qa_report(project_root)

    if qa_report_path is None or not qa_report_path.exists():
        print("No QA report found. Run QA Inspector first.")
        sys.exit(1)

    print(f"[Fixer] Using QA report {qa_report_path}")

    engine = GulfHisabFixerEngine(project_root=project_root, qa_report_path=qa_report_path, config=config)
    report = engine.run()

    output_path = project_root / "qa_reports" / f"fixer_report_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}.json"
    save_json(output_path, report_to_dict(report))

    print(f"Fixer report generated: {output_path}")
    print(json.dumps({
        "applied_count": report.applied_count,
        "skipped_count": report.skipped_count,
        "failed_count": report.failed_count,
        "escalations": report.escalations[:10],
    }, indent=2, ensure_ascii=False))


if __name__ == "__main__":
    main()
